    const __m512d tw8_re = _mm512_set1_pd(W_re[8]);
    const __m512d tw8_im = _mm512_set1_pd(W_im[8]);
    const __m512d tw9_re = _mm512_set1_pd(W_re[9]);
    const __m512d tw9_im = _mm512_set1_pd(W_im[9]);
